import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { archiveProduct, createProduct, listProducts } from "@/features/products/products-api"
import { productSchema } from "@/features/products/products-schema"

const productsKey = ["products"] as const

const readError = (error: unknown) => {
  if (typeof error === "object" && error && "response" in error) {
    const data = (error as { response?: { data?: { detail?: string; title?: string } } }).response?.data
    return data?.detail ?? data?.title ?? "Unable to save the product."
  }
  return "Unable to save the product."
}

export function Component() {
  const queryClient = useQueryClient()
  const [error, setError] = useState("")
  const products = useQuery({ queryKey: productsKey, queryFn: listProducts })
  const create = useMutation({
    mutationFn: createProduct,
    onSuccess: () => {
      setError("")
      queryClient.invalidateQueries({ queryKey: productsKey })
    },
    onError: (reason) => setError(readError(reason)),
  })
  const archive = useMutation({
    mutationFn: archiveProduct,
    onSuccess: () => queryClient.invalidateQueries({ queryKey: productsKey }),
    onError: (reason) => setError(readError(reason)),
