            {products.isError ? <p className="text-destructive" role="alert">{readError(products.error)}</p> : null}
            {products.data?.length === 0 ? <p className="text-muted-foreground">No active products yet.</p> : null}
            {products.data?.length ? <ul className="divide-y">{products.data.map((product) => <li className="flex items-center justify-between gap-4 py-3" key={product.id}><div><p className="font-medium">{product.name}</p><p className="text-sm text-muted-foreground">{product.sku}</p></div><Button disabled={archive.isPending} onClick={() => archive.mutate(product.id)} size="sm" variant="outline">Archive</Button></li>)}</ul> : null}
          </CardContent>
        </Card>
        <Card>
          <CardHeader><CardTitle>Add product</CardTitle></CardHeader>
          <CardContent>
            <form action={submit} className="space-y-4">
              <label className="block text-sm">Name<input className="mt-1 w-full rounded-md border bg-background p-2" name="name" required /></label>
              <label className="block text-sm">SKU<input className="mt-1 w-full rounded-md border bg-background p-2" name="sku" required /></label>
              {error ? <p className="text-sm text-destructive" role="alert">{error}</p> : null}
              <Button disabled={create.isPending} type="submit">{create.isPending ? "Adding…" : "Add product"}</Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}
